// 1. Enable Eureka Client on both services
@SpringBootApplication
@EnableDiscoveryClient 
public class OrderServiceApplication { ... }

// 2. Inter-service communication using Feign Client
// Instead of hardcoding "http://192.168.1.50:8081/inventory", 
// we just use the logical service name registered in Eureka.
import org.springframework.cloud.openfeign.FeignClient;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PathVariable;

@FeignClient(name = "inventory-service")
public interface InventoryClient {

    @GetMapping("/api/inventory/{productId}")
    boolean isProductInStock(@PathVariable Long productId);
}

// 3. Usage in Order Service
@Service
public class OrderService {
    private final InventoryClient inventoryClient;
    // constructor injection...

    public void placeOrder(Long productId) {
        // Makes a network call to the inventory service
        if (inventoryClient.isProductInStock(productId)) {
            System.out.println("Order placed!");
        } else {
            throw new RuntimeException("Out of stock");
        }
    }
}

